css:
.section-headline em { font-style: normal; font-weight: 700; color: var(--rouge); }
.hero-text { font-style: normal; }
.last-word-quote { font-style: normal; }
.quote-block-text { font-style: normal; }

.section-number { display: none; }
.section-label { margin-bottom: 12px; }
.section-title { font-size: 11px; letter-spacing: 2.5px; padding-left: 10px; border-left: 3px solid var(--rouge); line-height: 1; }

[data-section='injection_report'] .section-headline { font-family: 'DM Sans', sans-serif; font-size: 18px; font-weight: 700; letter-spacing: -0.2px; }
[data-section='injection_report'] .body-text strong { display: inline-block; font-size: 9px; letter-spacing: 2px; text-transform: uppercase; background: var(--rouge); color: #fff; padding: 2px 7px; border-radius: 2px; font-weight: 500; margin-right: 6px; vertical-align: middle; font-style: normal; }
[data-section='injection_report'] .highlight-box { border-left: 3px solid var(--rouge); background: transparent; color: var(--charcoal); border-radius: 0; padding: 10px 14px; font-size: 14px; }

[data-section='quick_hits'] .quick-hits-list { gap: 10px; }
[data-section='quick_hits'] .quick-hit-item { flex-direction: column; gap: 4px; padding: 14px; border: 1px solid var(--divider); border-bottom: 1px solid var(--divider); border-radius: 3px; background: var(--cream); }
[data-section='quick_hits'] .quick-hit-item:last-child { border-bottom: 1px solid var(--divider); }
[data-section='quick_hits'] .qh-emoji { display: none; }
[data-section='quick_hits'] .qh-label { display: inline-block; font-size: 9px; letter-spacing: 2px; text-transform: uppercase; background: var(--ink); color: var(--cream); padding: 2px 7px; border-radius: 2px; font-weight: 500; margin-bottom: 4px; }
